/bin/zsh -lc "python - <<'PY'
import csv, json
from decimal import Decimal, ROUND_HALF_UP

perf_mult = {'S': Decimal('3.0'), 'A': Decimal('2.0'), 'B': Decimal('1.0'), 'C': Decimal('0')}

def team_mult(score):
    if score >= Decimal('3.5'):
        return Decimal('1.2')
    if score >= Decimal('2.5'):
        return Decimal('1.0')
    return Decimal('0.8')

def seniority_mult(years):
    if years < Decimal('1'):
        return Decimal('0.5')
    if years < Decimal('3'):
        return Decimal('0.8')
    if years < Decimal('5'):
        return Decimal('1.0')
    if years < Decimal('10'):
        return Decimal('1.2')
    return Decimal('1.5')

rows = []
with open('input.csv', newline='', encoding='utf-8') as f:
    for row in csv.DictReader(f):
        base = Decimal(row['base_salary'])
        months = Decimal(row['months_worked'])
        perf = row['performance']
        if perf == 'C' or months < Decimal('6'):
            bonus = 0
        else:
            raw = base * perf_mult[perf] * team_mult(Decimal(row['team_avg_score'])) * seniority_mult(Decimal(row['seniority_years'])) * (months / Decimal('12'))
            capped = min(raw, base * Decimal('4'))
            bonus = int(capped.quantize(Decimal('1'), rounding=ROUND_HALF_UP))
        rows.append({'id': row['id'], 'bonus': bonus})

with open('output.json', 'w', encoding='utf-8') as f:
    json.dump(rows, f, ensure_ascii=False, indent=2)
    f.write('\\n')
PY
cat output.json"

